# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from flask_pymongo import PyMongo
from bson.json_util import dumps
from bson.objectid import ObjectId

app = Flask(__name__)
app.config["MONGO_URI"] = "mongodb://localhost:27017/cms"
mongo = PyMongo(app)


@app.route("/users", methods=["POST"])
def create_user():
    data = request.json
    user_id = mongo.db.users.insert_one(data).inserted_id
    return jsonify(str(user_id)), 201


@app.route("/users/<id>", methods=["GET"])
def get_user_profile(id):
    user = mongo.db.users.find_one({"_id": ObjectId(id)})
    if user:
        return dumps(user)
    else:
        return jsonify({"error": "User not found"}), 404


@app.route("/users/<id>", methods=["PUT"])
def update_user_profile(id):
    data = request.json
    mongo.db.users.update_one({"_id": ObjectId(id)}, {"$set": data})
    return jsonify({"message": "User profile updated successfully"}), 200


@app.route("/users", methods=["GET"])
def query_users():
    users_query = list(mongo.db.users.find())
    return dumps(users_query)


@app.route("/users/aggregate", methods=["GET"])
def aggregate_users():
    pipeline = request.json
    users_aggregate = mongo.db.users.aggregate(pipeline)
    return dumps(users_aggregate)


if __name__ == "__main__":
    app.run(debug=True)